import React from 'react';
import { 
  Box, 
  Avatar, 
  Typography, 
  useTheme, 
  alpha,
  Tooltip,
  styled
} from '@mui/material';
import { motion } from 'framer-motion';
import { useFirebase } from '../../context/FirebaseContext';

// Styled components
const CompanyCircleContainer = styled(Box)(({ theme }) => ({
  display: 'flex',
  alignItems: 'center',
  marginBottom: theme.spacing(4),
  padding: theme.spacing(1),
  gap: theme.spacing(2),
  overflowX: 'auto',
  scrollbarWidth: 'none',
  '&::-webkit-scrollbar': {
    display: 'none'
  },
}));

const MainCompanyCircle = styled(motion.div)(({ theme }) => ({
  position: 'relative',
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  cursor: 'pointer',
}));

const CompanyCircle = styled(motion.div)(({ theme }) => ({
  position: 'relative',
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  cursor: 'pointer',
}));

const CompanyName = styled(Typography)(({ theme }) => ({
  marginTop: theme.spacing(1.5),
  fontWeight: 700,
  fontSize: '0.9rem',
  textAlign: 'center',
  maxWidth: 110,
  whiteSpace: 'nowrap',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
}));

interface CompanySelectorProps {
  // Optional props if needed
}

const CompanySelector: React.FC<CompanySelectorProps> = () => {
  const theme = useTheme();
  const { companies, activeCompany, setActiveCompany, loading } = useFirebase();

  if (loading || companies.length === 0) {
    return null;
  }

  // Separate main company from others
  const mainCompany = companies.find(company => company.isMain) || companies[0];
  const otherCompanies = companies.filter(company => company.id !== mainCompany.id);

  const handleCompanyClick = (company: typeof companies[0]) => {
    setActiveCompany(company);
  };

  return (
    <CompanyCircleContainer>
      {/* Main company and other companies combined into one mapping */}
      {companies.map(company => {
        const isActive = activeCompany?.id === company.id;
        const isMainCompany = company.id === mainCompany.id;
        
        return (
          <Tooltip title={company.name} key={company.id}>
            <CompanyCircle
              onClick={() => handleCompanyClick(company)}
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
            >
              <Avatar 
                src={company.logo} 
                alt={company.name}
                sx={{
                  width: isActive ? 125 : 90,
                  height: isActive ? 125 : 90,
                  border: isActive
                    ? `4px solid ${company.color}` 
                    : `3px solid ${alpha(company.color, 0.2)}`,
                  boxShadow: isActive
                    ? `0 0 15px ${alpha(company.color, 0.6)}` 
                    : `0 2px 8px ${alpha(theme.palette.common.black, 0.08)}`,
                  transition: 'all 0.3s ease',
                  backgroundColor: 'transparent',
                  '& .MuiAvatar-img': {
                    objectFit: 'contain',
                    width: '100%',
                    height: '100%'
                  }
                }}
              />
              <CompanyName 
                variant={isActive ? "body2" : "caption"} 
                sx={{ 
                  fontSize: isActive ? '0.9rem' : '0.8rem',
                  fontWeight: isActive ? 700 : 600
                }}
              >
                {company.name}
              </CompanyName>
            </CompanyCircle>
          </Tooltip>
        );
      })}
    </CompanyCircleContainer>
  );
};

export default CompanySelector;
